# -*- coding: utf-8 -*-
# Additional quiz questions per module, targeting the deep-lecture content.
# QUIZ2[module_id] = [ {q,options[],answer,explain}, ... ]. build extends m['quiz'].
QUIZ2 = {0: [{'q': 'On the automation pyramid, which level does a PLC executing control logic occupy?', 'options': ['Level 0 - physical process', 'Level 1 - direct control', 'Level 3 - operations', 'Level 4 - enterprise'], 'answer': 1, 'explain': 'PLCs and safety controllers live at Level 1, directly controlling the Level 0 process.'}, {'q': 'A jam clears every time you cycle power to a device. Where does this most likely live?', 'options': ['Level 4 enterprise logic', 'Level 0-1 field device or output', 'Level 3 scheduling', 'The ERP system'], 'answer': 1, 'explain': 'A fault that clears on power-cycle is usually a sensor or output at Level 0-1, not high-level logic.'}, {'q': 'What best describes the AET technician role?', 'options': ['A pure programmer', 'A pure electrician', 'Someone who works across the electrical, controls, and mechanical overlap', 'A network administrator'], 'answer': 2, 'explain': 'AET lives in the overlap - enough of each domain to trace a fault across boundaries.'}], 1: [{'q': 'A 24V load reads 24V present but 0mA flowing. What does this indicate?', 'options': ['A short circuit', 'An open load (broken wire / blown internal fuse)', 'Correct operation', 'Too much current'], 'answer': 1, 'explain': 'Voltage present but no current means the circuit path is open - nothing is completing the loop.'}, {'q': 'In a start/stop seal-in, what keeps the motor running after you release Start?', 'options': ['The Stop button', 'The overload contact', 'The M auxiliary contact wired parallel to Start', 'The control transformer'], 'answer': 2, 'explain': 'The M aux NO contact, parallel with Start, keeps the coil energized after Start is released.'}, {'q': 'A 480V feed - roughly what is its peak voltage?', 'options': ['480V', '340V', '679V', '240V'], 'answer': 2, 'explain': 'Peak = RMS x sqrt(2), so 480 x 1.414 is about 679V. Insulation must survive the peak.'}], 2: [{'q': 'Why can a very short input pulse be missed by a PLC?', 'options': ['PLCs ignore inputs', 'If the pulse is shorter than one scan it may not be captured in the input image', 'Inputs are disabled during the program scan', 'The CPU is too fast'], 'answer': 1, 'explain': 'Inputs are sampled once per scan; a pulse faster than the scan time can fall between samples.'}, {'q': 'If the same output bit is written on two rungs in one scan, which wins?', 'options': ['The first rung', 'The last rung executed', 'Neither - it faults', 'They average'], 'answer': 1, 'explain': 'Because the program runs top-to-bottom and outputs write at scan end, the last rung wins.'}, {'q': 'A sensor tests good but the PLC input never turns on. A likely cause?', 'options': ['Scan time too fast', 'PNP/NPN sensor type mismatched to the input card', 'Too many rungs', 'The Stop button'], 'answer': 1, 'explain': 'A sourcing/sinking mismatch means the card never sees the expected signal even though the sensor works.'}], 3: [{'q': 'A CTU counter increments on what?', 'options': ['Every scan its rung is true', 'Each false-to-true transition of its rung', 'Only at power-up', 'When reset'], 'answer': 1, 'explain': 'Counters are edge-triggered - they count events (transitions), not held-true time.'}, {'q': 'In integer math, what does 5 / 2 evaluate to in a PLC?', 'options': ['2.5', '2', '3', 'Error'], 'answer': 1, 'explain': 'Integer division truncates - 5/2 is 2. Use floating point when you need 2.5.'}, {'q': 'A TOF (off-delay) timer does what?', 'options': ['Delays turning the output on', 'Keeps its output on for a set time after the rung goes false', 'Counts events', 'Never resets'], 'answer': 1, 'explain': 'TOF holds its output on for the preset time after its rung goes false - like a run-on fan.'}], 4: [{'q': 'Why does a 4-20mA loop read 4mA at zero instead of 0mA?', 'options': ['To waste power', 'Live zero - 0mA then clearly means a broken wire or dead transmitter', 'It is a calibration error', 'To match 0-10V'], 'answer': 1, 'explain': 'Live zero makes a fault (0mA) unmistakable versus a legitimate empty reading (4mA).'}, {'q': 'An incremental encoder tells direction using what?', 'options': ['A single pulse train', 'The phase relationship of quadrature A and B channels', 'Its color', 'The Z pulse only'], 'answer': 1, 'explain': 'A and B are 90 degrees out of phase; which leads tells direction, pulse rate tells speed.'}, {'q': 'Why does 4-20mA survive long noisy cable runs better than 0-10V?', 'options': ['It is a current loop, so wire resistance and voltage drop do not change the reading', 'It uses thicker wire', 'It is digital', 'It is higher voltage'], 'answer': 0, 'explain': 'Current is constant around a series loop regardless of wire resistance, so the reading holds.'}], 5: [{'q': 'A VFD trips on overvoltage during a fast stop. Best fix?', 'options': ['Speed up decel', 'Extend decel time or add a brake resistor', 'Increase max frequency', 'Lower the FLA setting'], 'answer': 1, 'explain': 'Fast decel on a high-inertia load pumps the DC bus up; slower decel or a brake resistor bleeds it off.'}, {'q': 'Constant Volts-per-Hertz control exists to keep what steady?', 'options': ['Current', 'Magnetic flux and torque', 'Temperature', 'Speed'], 'answer': 1, 'explain': 'Lowering voltage in proportion to frequency keeps flux (and thus torque capability) constant.'}, {'q': 'A drive faults on accel. Which category is most likely?', 'options': ['Bus overvoltage', 'Load/mechanical or too-fast ramp', 'Supply undervoltage at rest', 'Ambient temperature only'], 'answer': 1, 'explain': 'Accel faults point to load, a jam, or an aggressive ramp time - overcurrent territory.'}], 6: [{'q': 'A pneumatic cylinder is sluggish and sticky. A very common root cause?', 'options': ['Too much voltage', 'Clogged filter or a drifting regulator (air-quality/pressure)', 'Wrong PLC program', 'Encoder failure'], 'answer': 1, 'explain': 'Most pneumatic faults are air-prep problems - the FRL filter or regulator, not the cylinder.'}, {'q': 'Hydraulics can produce huge precise force mainly because oil is:', 'options': ['Compressible', 'Nearly incompressible', 'Electrically conductive', 'Lighter than air'], 'answer': 1, 'explain': 'Incompressible fluid transmits pressure fully (Pascal), giving strong, controllable force.'}, {'q': 'A solenoid valve will not shift. First electrical check?', 'options': ['Replace the cylinder', 'Meter the solenoid coil for its command voltage', 'Change the oil', 'Adjust the encoder'], 'answer': 1, 'explain': 'Many mechanical-seeming faults are really no signal reaching the coil - meter it first.'}], 7: [{'q': 'Under ISA-101 high-performance graphics, bright color is reserved for what?', 'options': ['Making screens attractive', 'Abnormal conditions so problems stand out', 'Every value', 'Company branding'], 'answer': 1, 'explain': 'A calm gray normal state with color only for abnormal lets a problem jump out.'}, {'q': 'An HMI value is frozen but the machine runs fine. Suspect first:', 'options': ['The motor', 'The tag binding, comm path, or update rate', 'The overload', 'The gearbox'], 'answer': 1, 'explain': 'A wrong/frozen display with healthy equipment usually means a tag/comm/poll-rate issue.'}, {'q': 'ISA-18.2 primarily addresses which problem?', 'options': ['Slow networks', 'Alarm floods and non-actionable alarms', 'Motor sizing', 'Wire colors'], 'answer': 1, 'explain': 'ISA-18.2 defines alarm rationalization so every alarm is actionable and prioritized.'}], 8: [{'q': 'Two EtherNet/IP devices with the same IP will:', 'options': ['Load-balance', 'Silently conflict and break communication', 'Run faster', 'Auto-renumber'], 'answer': 1, 'explain': 'A duplicate IP causes an address conflict that disrupts both devices.'}, {'q': 'OPC-UA is valued in IIoT because it is:', 'options': ['Windows-COM only', 'Vendor-neutral, secure, and platform-independent', 'A physical cable', 'A type of PLC'], 'answer': 1, 'explain': 'OPC-UA lets any compliant client read any compliant server securely, across vendors and platforms.'}, {'q': 'An intermittent network dropout near VFDs is most often:', 'options': ['A software bug', 'Physical - loose connector, cable damage, or EMI', 'A duplicate MAC only', 'Wrong programming language'], 'answer': 1, 'explain': 'Plant intermittents are usually physical layer, especially vibration and drive noise.'}], 9: [{'q': 'A linear (straight-line TCP) move is preferred over a joint move when:', 'options': ['Speed is the only goal', 'The tool must follow a controlled straight path for a process', 'The robot is off', 'Homing'], 'answer': 1, 'explain': 'Joint moves are fastest but the path is unpredictable; linear keeps the TCP straight for process work.'}, {'q': 'A cobot achieves safe operation near people mainly through:', 'options': ['Speed', 'Power-and-force limiting (senses contact and stops)', 'Being small', 'Bright paint'], 'answer': 1, 'explain': 'Collaborative robots limit power/force and stop on contact - but still need a risk assessment.'}, {'q': 'Before reaching into a robot envelope for maintenance you must:', 'options': ['Speed it up', 'Follow LOTO / safe-stop procedures', 'Remove the guarding permanently', 'Disable the E-stop'], 'answer': 1, 'explain': 'Never enter an energized envelope; LOTO and interlocks protect you from unexpected motion.'}], 10: [{'q': 'Which PID term eliminates steady-state offset?', 'options': ['Proportional', 'Integral', 'Derivative', 'None'], 'answer': 1, 'explain': 'Integral accumulates past error and keeps nudging until the offset is gone.'}, {'q': 'A loop overshoots and oscillates around setpoint. Likely cause?', 'options': ['Too little gain', 'Too much gain or integral', 'No feedback', 'Open loop'], 'answer': 1, 'explain': 'Excess gain/integral drives overshoot and hunting; back them off to stabilize.'}, {'q': 'On a P&ID, a balloon tagged FIC means:', 'options': ['Field indicator cabinet', 'Flow Indicating Controller', 'Fixed input channel', 'Fault interlock circuit'], 'answer': 1, 'explain': 'ISA-5.1: F=flow (variable), I=indicate, C=control - a Flow Indicating Controller.'}], 11: [{'q': 'The hierarchy of controls ranks which method highest?', 'options': ['PPE', 'Administrative procedures', 'Eliminate or design out the hazard', 'Warning signs'], 'answer': 2, 'explain': 'Elimination/design-out is most reliable because it does not depend on human behavior.'}, {'q': 'A high-risk safety function per ISO 13849 generally requires:', 'options': ['A single ordinary switch', 'Redundant, monitored (self-checking) architecture', 'No wiring', 'Only a warning label'], 'answer': 1, 'explain': 'Higher required Performance Levels need redundancy and diagnostics so one failure does not defeat safety.'}, {'q': 'During LOTO, verifying zero energy means:', 'options': ['Trusting the schematic', 'Attempting to start the machine and confirming it cannot run', 'Asking a coworker', 'Reading the nameplate'], 'answer': 1, 'explain': 'You physically verify isolation - try to start it and confirm no motion / no voltage.'}], 12: [{'q': 'The integration mindset means:', 'options': ['Assuming the cause immediately', 'Tracing the signal chain across every domain until evidence points to one link', 'Swapping parts until it works', 'Only checking the PLC'], 'answer': 1, 'explain': 'Faults hide in the seams; you follow the chain across electrical/controls/mechanical/network.'}, {'q': 'The golden rule of commissioning order is:', 'options': ['Run at full rate first', 'Never energize or run a sequence until the layer beneath it is proven', 'Skip I/O checks', 'Test alarms last'], 'answer': 1, 'explain': 'Work bottom-up: wiring, then point I/O, then functions, then integrated operation.'}], 13: [{'q': 'A key drawback of Structured Text versus ladder is:', 'options': ['It cannot do math', 'You cannot watch power flow live, making it harder to troubleshoot', 'It is slower always', 'It has no loops'], 'answer': 1, 'explain': "ST is great for math/logic but lacks ladder's live power-flow visibility."}, {'q': 'The main benefit of an AOI (Add-On Instruction) is:', 'options': ['Faster scan always', 'Reusable, tested logic - fix once and it propagates to every instance', 'Smaller wires', 'No tags needed'], 'answer': 1, 'explain': 'AOIs encapsulate tested logic for reuse and consistency across many identical devices.'}, {'q': 'A state machine makes a sequence easier to troubleshoot because:', 'options': ['It uses more timers', 'The machine is in exactly one defined state with defined transitions', 'It hides the logic', 'It runs backward'], 'answer': 1, 'explain': "You can always ask 'what state am I in and why won't I transition' - behavior is explicit."}], 14: [{'q': 'Why keep latency-critical processing at the edge rather than the cloud?', 'options': ['The cloud is cheaper', 'Fast local decisions and uptime if the internet drops; less bandwidth', 'Edge is more secure always', 'Regulations forbid cloud'], 'answer': 1, 'explain': 'Edge handles fast/local work and keeps running offline; cloud does storage and cross-site analytics.'}, {'q': 'MQTT scales to many sensors because it uses:', 'options': ['Constant polling', 'Publish/subscribe through a broker that decouples devices', 'One wire per sensor', 'Email'], 'answer': 1, 'explain': 'Publishers post to topics on a broker; subscribers pull what they care about - no direct coupling.'}, {'q': 'A core concept of IEC 62443 OT security is:', 'options': ['Open all ports', 'Zones and conduits with controlled connections', 'One password for all', 'No firewalls'], 'answer': 1, 'explain': 'Group assets into security zones and tightly control the conduits between them.'}], 15: [{'q': 'The live-dead-live check means:', 'options': ['Testing three circuits', 'Verify the meter on a known live source before and after testing the isolated circuit', 'Measuring three times', 'Using three meters'], 'answer': 1, 'explain': 'Prove the meter works on known voltage, confirm the circuit is dead, then re-verify the meter.'}, {'q': 'A high-resistance connection under load is best found by:', 'options': ['A resistance test with power off', 'Measuring voltage drop across it under load', 'Guessing', 'Replacing all wires'], 'answer': 1, 'explain': 'Voltage drop under load reveals high resistance a de-energized ohm test can miss.'}, {'q': 'A megohmmeter differs from an ohmmeter because it:', 'options': ['Uses low voltage', 'Applies high DC voltage to test insulation resistance', 'Only tests continuity', 'Measures current'], 'answer': 1, 'explain': 'A megger applies hundreds of volts to measure insulation in the megohm+ range - catches breakdown early.'}], 16: [{'q': 'Which metric measures how quickly you recover after a failure?', 'options': ['MTBF', 'MTTR', 'OEE', 'DPMO'], 'answer': 1, 'explain': 'MTTR (Mean Time To Repair) is recovery speed; MTBF is reliability between failures.'}, {'q': 'A 1x-running-speed vibration peak most classically indicates:', 'options': ['Bearing defect', 'Imbalance', 'Electrical fault', 'Cavitation'], 'answer': 1, 'explain': 'Imbalance shows at 1x; misalignment at 1x/2x; looseness as many harmonics; bearings at high frequencies.'}, {'q': 'Predictive maintenance aims to:', 'options': ['Run to failure', 'Service strictly on a fixed calendar', 'Fix things just before they fail using condition monitoring', 'Never do maintenance'], 'answer': 2, 'explain': 'PdM uses vibration/thermography/oil/insulation trends to act just before failure - the sweet spot for critical assets.'}], 17: [{'q': "A panel's SCCR must:", 'options': ['Be as low as possible', 'Exceed the available fault current at its location', 'Match the wire color', 'Equal the motor HP'], 'answer': 1, 'explain': 'Short-Circuit Current Rating must exceed available fault current or the panel is unsafe/non-compliant.'}, {'q': 'Power and low-level signal wiring should be:', 'options': ['Bundled together', 'Routed separately to avoid coupling drive/motor noise into signals', 'Removed', 'The same gauge'], 'answer': 1, 'explain': 'Separation prevents VFD/motor noise from corrupting sensor and comm circuits - a top cause of phantom faults.'}, {'q': 'The number-one cause of intermittent, heat-generating panel faults is:', 'options': ['Too many labels', 'Loose terminal connections', 'Correct torque', 'Neat wire duct'], 'answer': 1, 'explain': 'Loose terminals arc, heat, and cause intermittents - torque to spec and tug-test.'}], 18: [{'q': 'The strongest content for a technical portfolio is:', 'options': ['A list of job titles', 'Problems you solved with quantified before/action/result', 'Your hobbies', 'Salary history'], 'answer': 1, 'explain': 'Concrete solved problems (ideally with numbers) prove capability and make interview stories easy.'}, {'q': "For a 'walk me through how you would fix X' interview question, you should:", 'options': ['Guess a part', 'Use your systematic method out loud - define, gather, hypothesize, test, verify', 'Refuse', 'Only name tools'], 'answer': 1, 'explain': 'They test how you think; narrating a systematic method shows disciplined troubleshooting.'}, {'q': 'When choosing a certification, best practice is to:', 'options': ['Chase the most certs', "Pick ones matching your site's equipment or your next role", 'Avoid all certs', 'Only pick the cheapest'], 'answer': 1, 'explain': 'A cert that matches your gear/role makes the studying double as job skill and carries real weight.'}]}
